+  private getCursorPagination(opts: CrudOptions): {
+    orderBy: Record<string, 'asc' | 'desc'>[];
+    sort: Array<{ field: string; direction: 'asc' | 'desc' }>;
+    cursor?: Record<string, any>;
+  } | null {
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    if (!opts.orderBy) {
+      return null;
+    }
+
+    const orderByItems = Array.isArray(opts.orderBy)
+      ? opts.orderBy
+      : [opts.orderBy];
+    const sort = orderByItems.flatMap((item) =>
+      Object.entries(item).map(([field, value]) => ({
+        field,
+        direction: this.normalizeCursorDirection(value),
+      })),
+    );
+    const idField = this.crudConfig.id_field as string;
+    if (!sort.some((item) => item.field === idField)) {
+      sort.push({ field: idField, direction: 'asc' });
+    }
+    const orderBy = sort.map(({ field, direction }) => ({ [field]: direction }));
+    const cursor = opts.cursor
+      ? this.decodeCursor(opts.cursor, sort, idField)
+      : undefined;
+    return { orderBy, sort, cursor };
+  }
+
+  private normalizeCursorDirection(value: unknown): 'asc' | 'desc' {
+    const direction = String(value).toLowerCase();
+    if (direction === 'asc' || direction === 'desc') {
+      return direction;
+    }
+    throw new BadRequestException('cursor pagination requires asc or desc orderBy directions');
+  }
+
+  private decodeCursor(
+    encoded: string,
+    sort: Array<{ field: string; direction: 'asc' | 'desc' }>,
+    idField: string,
+  ): Record<string, any> {
+    let cursor: Record<string, any>;
+    try {
+      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(encoded) || encoded.length % 4 !== 0) {
+        throw new Error('invalid base64');
+      }
+      const decoded = Buffer.from(encoded, 'base64').toString('utf8');
+      cursor = JSON.parse(decoded);
+      if (!cursor || Array.isArray(cursor) || typeof cursor !== 'object') {
+        throw new Error('invalid cursor payload');
+      }
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded valid JSON');
+    }
+    if (!(idField in cursor)) {
+      throw new BadRequestException(`cursor is missing ${idField}`);
+    }
+    const expectedSort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const { field } of sort) {
+      if (!(field in cursor)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    return cursor;
+  }
+
+  private addCursorCondition(
+    entity: Partial<T>,
+    pagination: {
+      sort: Array<{ field: string; direction: 'asc' | 'desc' }>;
+      cursor?: Record<string, any>;
+    },
+  ): Partial<T> {
+    if (!pagination.cursor) {
+      return entity;
+    }
+    const comparisons = pagination.sort.map(({ field, direction }, index) => {
+      const equalBefore = pagination.sort.slice(0, index).reduce(
+        (query, previous) => ({ ...query, [previous.field]: pagination.cursor[previous.field] }),
+        {},
+      );
+      return {
+        ...equalBefore,
+        [field]: { [direction === 'asc' ? '$gt' : '$lt']: pagination.cursor[field] },
+      };
+    });
+    return { $and: [entity, { $or: comparisons }] } as Partial<T>;
+  }
+
+  private encodeCursor(
